import{c as e,Q as o,j as r,m as a}from"./chunks/framework.rlpw0eGz.js";const m=JSON.parse('{"title":"渠道总览","description":"","frontmatter":{},"headers":[],"relativePath":"zh/channels/index.md","filePath":"zh/channels/index.md","lastUpdated":1777012567000}'),l={name:"zh/channels/index.md"};function n(i,t,s,h,g,d){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="渠道总览" tabindex="-1">渠道总览 <a class="header-anchor" href="#渠道总览" aria-label="Permalink to &quot;渠道总览&quot;">​</a></h1><p><strong>渠道</strong>把 Memoh 机器人和外面连起来；配好以后，你就能在常用 IM 里用机器人。</p><p>当前支持：</p><ul><li><strong><a href="./slack.html">Slack</a></strong>：Socket Mode、频道与 thread、文件、反应。</li><li><strong><a href="./telegram.html">Telegram</a></strong>：流式、附件、格式等较全。</li><li><strong><a href="./feishu.html">飞书</a></strong>：开放平台，偏企业流程。</li><li><strong><a href="./discord.html">Discord</a></strong>：服务器与私聊。</li><li><strong><a href="./qq.html">QQ</a></strong>：官方机器人平台，个人 DM 向。</li><li><strong><a href="./matrix.html">Matrix</a></strong>：任意 homeserver，去中心化协议。</li><li><strong><a href="./misskey.html">Misskey</a></strong>：回复、反应；偏文字社交。</li><li><strong><a href="./dingtalk.html">钉钉</a></strong>：企业私聊/群，流式入站。</li><li><strong><a href="./wecom.html">企微 WeCom</a></strong>：企业微信工作区。</li><li><strong><a href="./weixin.html">微信</a></strong>：个人号，扫码登录。</li><li><strong><a href="./wechatoa.html">微信公众号</a></strong>：服务号/公众号 webhook，偏私聊入站。</li><li><strong>邮件</strong>：SMTP、Mailgun、Gmail OAuth 等，在「邮件提供方」里配，见 <a href="/zh/getting-started/email.html">邮件</a>。</li><li><strong>Web</strong>：自带网页聊天。</li></ul><h3 id="个人微信-和-公众号" tabindex="-1">个人微信 和 公众号 <a class="header-anchor" href="#个人微信-和-公众号" aria-label="Permalink to &quot;个人微信 和 公众号&quot;">​</a></h3><p>两套东西不要混：</p><ul><li><strong>微信（<code>weixin</code>）</strong>：个人号扫码连上那种。</li><li><strong>公众号（<code>wechatoa</code>）</strong>：要 <code>App ID</code>、<code>App Secret</code>、<code>Token</code>，可选加解密；走平台回调 URL。</li></ul><p>按你实际部署选一种。</p><h2 id="一般怎么配" tabindex="-1">一般怎么配 <a class="header-anchor" href="#一般怎么配" aria-label="Permalink to &quot;一般怎么配&quot;">​</a></h2><ol><li>在目标平台注册应用/机器人，拿 token、密钥等。</li><li>在 Memoh 里该机器人的 <strong>Platforms</strong> 里加渠道，按表单填。</li><li>保存并启用。</li></ol><p>最后一步因平台而异：有的要把 <strong>回调 URL</strong> 粘到控制台，有的要 <strong>手机扫码</strong>，有的要 <strong>长连接/WebSocket</strong> 一直由 Memoh 维护。下面分平台见各篇。</p>',11)])])}const p=e(l,[["render",n]]);export{m as __pageData,p as default};
